package com.securebank.app.security;

import java.io.File;

public class RootDetector {

    private static final String[] ROOT_INDICATORS = {
            "/system/app/Superuser.apk",
            "/system/xbin/su",
            "/system/bin/su",
            "/sbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/data/local/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/su/bin/su"
    };

    private static final String[] DANGEROUS_PACKAGES = {
            "com.noshufou.android.su",
            "com.thirdparty.superuser",
            "eu.chainfire.supersu",
            "com.koushikdutta.superuser",
            "com.zachspong.temprootremovejb",
            "com.ramdroid.appquarantine",
            "com.topjohnwu.magisk"
    };

    public static boolean isDeviceRooted() {
        return checkRootBinaries() || checkSuExists();
    }

    private static boolean checkRootBinaries() {
        for (String path : ROOT_INDICATORS) {
            if (new File(path).exists()) {
                return true;
            }
        }
        return false;
    }

    private static boolean checkSuExists() {
        try {
            Process process = Runtime.getRuntime().exec(new String[]{"which", "su"});
            int exitValue = process.waitFor();
            return exitValue == 0;
        } catch (Exception e) {
            return false;
        }
    }
}

