package com.securebank.app.security;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public class InputValidator {

    private static final Pattern ACCOUNT_NUMBER_PATTERN =
            Pattern.compile("^[0-9]{8,20}$");

    private static final Pattern AMOUNT_PATTERN =
            Pattern.compile("^[0-9]+(\\.[0-9]{1,2})?$");

    private static final Pattern DESCRIPTION_PATTERN =
            Pattern.compile("^[a-zA-Z0-9\\s\\-_.,!?()]{0,200}$");

    private static final Pattern PIN_PATTERN =
            Pattern.compile("^[0-9]{4,8}$");

    private static final Pattern USERNAME_PATTERN =
            Pattern.compile("^[a-zA-Z0-9._@\\-]{3,50}$");

    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");

    public static ValidationResult validateAccountNumber(String accountNumber) {
        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            return new ValidationResult(false, "Account number is required");
        }
        if (!ACCOUNT_NUMBER_PATTERN.matcher(accountNumber.trim()).matches()) {
            return new ValidationResult(false, "Invalid account number format");
        }
        return new ValidationResult(true, null);
    }

    public static ValidationResult validateAmount(String amountStr) {
        if (amountStr == null || amountStr.trim().isEmpty()) {
            return new ValidationResult(false, "Amount is required");
        }
        if (!AMOUNT_PATTERN.matcher(amountStr.trim()).matches()) {
            return new ValidationResult(false, "Invalid amount format");
        }
        try {
            BigDecimal amount = new BigDecimal(amountStr.trim());
            if (amount.compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
                return new ValidationResult(false,
                        "Minimum transaction amount is " + MIN_TRANSACTION_AMOUNT);
            }
            if (amount.compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
                return new ValidationResult(false,
                        "Maximum transaction amount is " + MAX_TRANSACTION_AMOUNT);
            }
            return new ValidationResult(true, null);
        } catch (NumberFormatException e) {
            return new ValidationResult(false, "Invalid amount");
        }
    }

    public static ValidationResult validateDescription(String description) {
        if (description == null || description.trim().isEmpty()) {
            return new ValidationResult(true, null);
        }
        if (!DESCRIPTION_PATTERN.matcher(description).matches()) {
            return new ValidationResult(false,
                    "Description contains invalid characters (max 200 chars)");
        }
        return new ValidationResult(true, null);
    }

    public static ValidationResult validatePin(String pin) {
        if (pin == null || pin.trim().isEmpty()) {
            return new ValidationResult(false, "PIN is required");
        }
        if (!PIN_PATTERN.matcher(pin).matches()) {
            return new ValidationResult(false, "PIN must be 4-8 digits");
        }
        if (isWeakPin(pin)) {
            return new ValidationResult(false,
                    "PIN is too weak. Avoid sequential or repeated digits");
        }
        return new ValidationResult(true, null);
    }

    public static ValidationResult validateUsername(String username) {
        if (username == null || username.trim().isEmpty()) {
            return new ValidationResult(false, "Username is required");
        }
        if (!USERNAME_PATTERN.matcher(username.trim()).matches()) {
            return new ValidationResult(false, "Invalid username format");
        }
        return new ValidationResult(true, null);
    }

    public static String sanitize(String input) {
        if (input == null) return null;
        return input.trim()
                .replaceAll("[<>\"';&|]", "")
                .replaceAll("\\s+", " ");
    }

    private static boolean isWeakPin(String pin) {
        if (pin.chars().distinct().count() == 1) return true;

        boolean sequential = true;
        for (int i = 1; i < pin.length(); i++) {
            if (pin.charAt(i) - pin.charAt(i - 1) != 1) {
                sequential = false;
                break;
            }
        }
        if (sequential) return true;

        boolean reverseSequential = true;
        for (int i = 1; i < pin.length(); i++) {
            if (pin.charAt(i - 1) - pin.charAt(i) != 1) {
                reverseSequential = false;
                break;
            }
        }
        return reverseSequential;
    }

    public static class ValidationResult {
        private final boolean valid;
        private final String errorMessage;

        public ValidationResult(boolean valid, String errorMessage) {
            this.valid = valid;
            this.errorMessage = errorMessage;
        }

        public boolean isValid() { return valid; }
        public String getErrorMessage() { return errorMessage; }
    }
}

