import android.util.Log;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import com.securebank.app.security.SecurityManager;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.CertificatePinner;
import okhttp3.Interceptor;
import okhttp3.MediaType;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

public class SecureApiClient {

    private static final String TAG = "SecureApiClient";
    private static final String BASE_URL = "https://api.securebank.com/v1";
    private static final MediaType JSON = MediaType.parse("application/json; charset=utf-8");

    private static SecureApiClient instance;
    private final OkHttpClient client;
    private final Gson gson;

    private SecureApiClient() {
        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add("api.securebank.com",
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                .add("api.securebank.com",
                        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
                .build();

        client = new OkHttpClient.Builder()
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(30, TimeUnit.SECONDS)
                .writeTimeout(30, TimeUnit.SECONDS)
                .certificatePinner(certificatePinner)
                .addInterceptor(new AuthInterceptor())
                .addInterceptor(new LoggingInterceptor())
                .build();

        gson = new GsonBuilder()
                .setDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
                .create();
    }

    public static synchronized SecureApiClient getInstance() {
        if (instance == null) {
            instance = new SecureApiClient();
        }
        return instance;
    }

    public Response executeGet(String endpoint) throws IOException {
        Request request = new Request.Builder()
                .url(BASE_URL + endpoint)
                .get()
                .build();
        return client.newCall(request).execute();
    }

    public Response executePost(String endpoint, Object body) throws IOException {
        String jsonBody = gson.toJson(body);
        RequestBody requestBody = RequestBody.create(jsonBody, JSON);

        Request request = new Request.Builder()
                .url(BASE_URL + endpoint)
                .post(requestBody)
                .build();
        return client.newCall(request).execute();
    }

    public Response executePost(String endpoint, Object body, String idempotencyKey) throws IOException {
        String jsonBody = gson.toJson(body);
        RequestBody requestBody = RequestBody.create(jsonBody, JSON);

        Request request = new Request.Builder()
                .url(BASE_URL + endpoint)
                .post(requestBody)
                .addHeader("Idempotency-Key", idempotencyKey)
                .build();
        return client.newCall(request).execute();
    }

    public Gson getGson() { return gson; }

    private static class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request originalRequest = chain.request();

            SecurityManager securityManager = SecurityManager.getInstance();
            String token = securityManager.getAuthToken();

            if (token != null) {
                String nonce = SecurityManager.generateNonce();

                Request authenticatedRequest = originalRequest.newBuilder()
                        .addHeader("Authorization", "Bearer " + token)
                        .addHeader("X-Request-Nonce", nonce)
                        .addHeader("X-Client-Version", "1.0.0")
                        .addHeader("X-Platform", "Android")
                        .build();
                return chain.proceed(authenticatedRequest);
            }

            return chain.proceed(originalRequest);
        }
    }

    private static class LoggingInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request request = chain.request();
            long startTime = System.nanoTime();

            Log.d(TAG, String.format("Sending request to %s", request.url()));

            Response response = chain.proceed(request);

            long duration = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime);
            Log.d(TAG, String.format("Received response %d from %s in %dms",
                    response.code(), response.request().url(), duration));

            return response;
        }
    }
}

