package com.securebank.app.service;

import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.google.gson.Gson;
import com.google.gson.reflect.TypeToken;
import com.securebank.app.model.Account;
import com.securebank.app.model.Transaction;
import com.securebank.app.model.TransactionResult;
import com.securebank.app.network.SecureApiClient;
import com.securebank.app.security.InputValidator;

import java.io.IOException;
import java.lang.reflect.Type;
import java.math.BigDecimal;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import okhttp3.Response;
import okhttp3.ResponseBody;

public class TransactionService {

    private static final String TAG = "TransactionService";

    public interface TransactionCallback {
        void onSuccess(TransactionResult result);
        void onError(String errorMessage, String errorCode);
    }

    public interface AccountCallback {
        void onSuccess(List<Account> accounts);
        void onError(String errorMessage);
    }

    public interface BalanceCallback {
        void onSuccess(Account account);
        void onError(String errorMessage);
    }

    public interface TransactionHistoryCallback {
        void onSuccess(List<Transaction> transactions);
        void onError(String errorMessage);
    }

    private static TransactionService instance;
    private final SecureApiClient apiClient;
    private final ExecutorService executorService;
    private final Handler mainHandler;

    private TransactionService() {
        apiClient = SecureApiClient.getInstance();
        executorService = Executors.newFixedThreadPool(3);
        mainHandler = new Handler(Looper.getMainLooper());
    }

    public static synchronized TransactionService getInstance() {
        if (instance == null) {
            instance = new TransactionService();
        }
        return instance;
    }

    public void processTransfer(Transaction transaction, TransactionCallback callback) {
        InputValidator.ValidationResult accountValidation =
                InputValidator.validateAccountNumber(transaction.getToAccountNumber());
        if (!accountValidation.isValid()) {
            callback.onError(accountValidation.getErrorMessage(), "INVALID_ACCOUNT");
            return;
        }

        InputValidator.ValidationResult amountValidation =
                InputValidator.validateAmount(transaction.getAmount().toPlainString());
        if (!amountValidation.isValid()) {
            callback.onError(amountValidation.getErrorMessage(), "INVALID_AMOUNT");
            return;
        }

        if (transaction.getDescription() != null) {
            InputValidator.ValidationResult descValidation =
                    InputValidator.validateDescription(transaction.getDescription());
            if (!descValidation.isValid()) {
                callback.onError(descValidation.getErrorMessage(), "INVALID_DESCRIPTION");
                return;
            }
            transaction.setDescription(InputValidator.sanitize(transaction.getDescription()));
        }

        executorService.execute(() -> {
            try {
                Map<String, Object> requestBody = new HashMap<>();
                requestBody.put("fromAccountId", transaction.getFromAccountId());
                requestBody.put("toAccountNumber", transaction.getToAccountNumber());
                requestBody.put("beneficiaryName",
                        InputValidator.sanitize(transaction.getBeneficiaryName()));
                requestBody.put("amount", transaction.getAmount().toPlainString());
                requestBody.put("currency", transaction.getCurrency());
                requestBody.put("description", transaction.getDescription());
                requestBody.put("transactionType", transaction.getType().name());

                Response response = apiClient.executePost(
                        "/transactions/transfer",
                        requestBody,
                        transaction.getIdempotencyKey()
                );

                handleTransactionResponse(response, transaction, callback);

            } catch (IOException e) {
                Log.e(TAG, "Transfer failed", e);
                mainHandler.post(() ->
                        callback.onError("Network error. Please check your connection.",
                                "NETWORK_ERROR"));
            } catch (Exception e) {
                Log.e(TAG, "Unexpected error during transfer", e);
                mainHandler.post(() ->
                        callback.onError("An unexpected error occurred. Please try again.",
                                "UNKNOWN_ERROR"));
            }
        });
    }

    public void getAccountBalance(String accountId, BalanceCallback callback) {
        executorService.execute(() -> {
            try {
                Response response = apiClient.executeGet("/accounts/" + accountId + "/balance");

                if (response.isSuccessful()) {
                    ResponseBody body = response.body();
                    if (body != null) {
                        String json = body.string();
                        Account account = apiClient.getGson().fromJson(json, Account.class);
                        mainHandler.post(() -> callback.onSuccess(account));
                    } else {
                        mainHandler.post(() -> callback.onError("Empty response from server"));
                    }
                } else {
                    String errorMsg = parseErrorMessage(response);
                    mainHandler.post(() -> callback.onError(errorMsg));
                }

                response.close();

            } catch (IOException e) {
                Log.e(TAG, "Failed to fetch balance", e);
                mainHandler.post(() ->
                        callback.onError("Network error. Please check your connection."));
            }
        });
    }

    public void getAccounts(AccountCallback callback) {
        executorService.execute(() -> {
            try {
                Response response = apiClient.executeGet("/accounts");

                if (response.isSuccessful()) {
                    ResponseBody body = response.body();
                    if (body != null) {
                        String json = body.string();
                        Type listType = new TypeToken<List<Account>>() {}.getType();
                        List<Account> accounts = apiClient.getGson().fromJson(json, listType);
                        mainHandler.post(() -> callback.onSuccess(accounts));
                    } else {
                        mainHandler.post(() -> callback.onError("Empty response from server"));
                    }
                } else {
                    String errorMsg = parseErrorMessage(response);
                    mainHandler.post(() -> callback.onError(errorMsg));
                }

                response.close();

            } catch (IOException e) {
                Log.e(TAG, "Failed to fetch accounts", e);
                mainHandler.post(() ->
                        callback.onError("Network error. Please check your connection."));
            }
        });
    }

    public void getTransactionHistory(String accountId, int page, int limit,
                                       TransactionHistoryCallback callback) {
        executorService.execute(() -> {
            try {
                String endpoint = String.format("/accounts/%s/transactions?page=%d&limit=%d",
                        accountId, page, limit);
                Response response = apiClient.executeGet(endpoint);

                if (response.isSuccessful()) {
                    ResponseBody body = response.body();
                    if (body != null) {
                        String json = body.string();
                        Type listType = new TypeToken<List<Transaction>>() {}.getType();
                        List<Transaction> transactions =
                                apiClient.getGson().fromJson(json, listType);
                        mainHandler.post(() -> callback.onSuccess(transactions));
                    } else {
                        mainHandler.post(() -> callback.onError("Empty response from server"));
                    }
                } else {
                    String errorMsg = parseErrorMessage(response);
                    mainHandler.post(() -> callback.onError(errorMsg));
                }

                response.close();

            } catch (IOException e) {
                Log.e(TAG, "Failed to fetch transaction history", e);
                mainHandler.post(() ->
                        callback.onError("Network error. Please check your connection."));
            }
        });
    }

    private void handleTransactionResponse(Response response, Transaction transaction,
                                            TransactionCallback callback) throws IOException {
        try {
            if (response.isSuccessful()) {
                ResponseBody body = response.body();
                if (body != null) {
                    String json = body.string();
                    Gson gson = apiClient.getGson();

                    Map<String, Object> responseMap = gson.fromJson(json,
                            new TypeToken<Map<String, Object>>() {}.getType());

                    String referenceNumber = (String) responseMap.get("referenceNumber");
                    transaction.setReferenceNumber(referenceNumber);
                    transaction.setStatus(Transaction.TransactionStatus.COMPLETED);

                    TransactionResult result = TransactionResult.success(
                            "Transfer completed successfully",
                            referenceNumber,
                            transaction
                    );

                    mainHandler.post(() -> callback.onSuccess(result));
                } else {
                    mainHandler.post(() ->
                            callback.onError("Empty response from server", "EMPTY_RESPONSE"));
                }
            } else {
                String errorMsg = parseErrorMessage(response);
                String errorCode = String.valueOf(response.code());

                transaction.setStatus(Transaction.TransactionStatus.FAILED);

                mainHandler.post(() -> callback.onError(errorMsg, errorCode));
            }
        } finally {
            response.close();
        }
    }

    private String parseErrorMessage(Response response) {
        try {
            ResponseBody body = response.body();
            if (body != null) {
                String json = body.string();
                Map<String, Object> errorMap = apiClient.getGson().fromJson(json,
                        new TypeToken<Map<String, Object>>() {}.getType());
                if (errorMap != null && errorMap.containsKey("message")) {
                    return (String) errorMap.get("message");
                }
            }
        } catch (Exception e) {
            Log.e(TAG, "Failed to parse error response", e);
        }

        switch (response.code()) {
            case 400: return "Invalid request. Please check your input.";
            case 401: return "Session expired. Please log in again.";
            case 403: return "You don't have permission to perform this action.";
            case 404: return "Account not found.";
            case 409: return "Duplicate transaction detected.";
            case 422: return "Insufficient funds.";
            case 429: return "Too many requests. Please wait and try again.";
            case 500: return "Server error. Please try again later.";
            case 503: return "Service temporarily unavailable.";
            default: return "An error occurred. Please try again.";
        }
    }
}

