package com.securebank.app.service;

import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.google.gson.reflect.TypeToken;
import com.securebank.app.model.AuthToken;
import com.securebank.app.network.SecureApiClient;
import com.securebank.app.security.InputValidator;
import com.securebank.app.security.SecurityManager;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import okhttp3.Response;
import okhttp3.ResponseBody;

public class AuthService {

    private static final String TAG = "AuthService";

    public interface AuthCallback {
        void onSuccess();
        void onError(String errorMessage);
    }

    private static AuthService instance;
    private final SecureApiClient apiClient;
    private final SecurityManager securityManager;
    private final ExecutorService executorService;
    private final Handler mainHandler;

    private AuthService() {
        apiClient = SecureApiClient.getInstance();
        securityManager = SecurityManager.getInstance();
        executorService = Executors.newSingleThreadExecutor();
        mainHandler = new Handler(Looper.getMainLooper());
    }

    public static synchronized AuthService getInstance() {
        if (instance == null) {
            instance = new AuthService();
        }
        return instance;
    }

    public void login(String username, String pin, AuthCallback callback) {
        InputValidator.ValidationResult usernameValidation =
                InputValidator.validateUsername(username);
        if (!usernameValidation.isValid()) {
            callback.onError(usernameValidation.getErrorMessage());
            return;
        }

        InputValidator.ValidationResult pinValidation = InputValidator.validatePin(pin);
        if (!pinValidation.isValid()) {
            callback.onError(pinValidation.getErrorMessage());
            return;
        }

        executorService.execute(() -> {
            try {
                Map<String, String> requestBody = new HashMap<>();
                requestBody.put("username", InputValidator.sanitize(username));
                requestBody.put("pin", pin);
                requestBody.put("deviceId", SecurityManager.generateNonce());

                Response response = apiClient.executePost("/auth/login", requestBody);

                if (response.isSuccessful()) {
                    ResponseBody body = response.body();
                    if (body != null) {
                        String json = body.string();
                        Map<String, Object> responseMap = apiClient.getGson().fromJson(json,
                                new TypeToken<Map<String, Object>>() {}.getType());

                        String accessToken = (String) responseMap.get("accessToken");
                        String refreshToken = (String) responseMap.get("refreshToken");
                        double expiresIn = (Double) responseMap.get("expiresIn");
                        long expiresAt = System.currentTimeMillis() +
                                (long) (expiresIn * 1000);

                        securityManager.storeAuthToken(accessToken, refreshToken, expiresAt);

                        if (responseMap.containsKey("sessionId")) {
                            securityManager.storeSessionId(
                                    (String) responseMap.get("sessionId"));
                        }

                        mainHandler.post(callback::onSuccess);
                    } else {
                        mainHandler.post(() ->
                                callback.onError("Empty response from server"));
                    }
                } else {
                    String errorMsg = response.code() == 401 ?
                            "Invalid username or PIN" :
                            "Login failed. Please try again.";
                    mainHandler.post(() -> callback.onError(errorMsg));
                }

                response.close();

            } catch (IOException e) {
                Log.e(TAG, "Login failed", e);
                mainHandler.post(() ->
                        callback.onError("Network error. Please check your connection."));
            }
        });
    }

    public void logout(AuthCallback callback) {
        executorService.execute(() -> {
            try {
                apiClient.executePost("/auth/logout", new HashMap<>());
            } catch (IOException e) {
                Log.e(TAG, "Logout API call failed", e);
            } finally {
                securityManager.clearAuthToken();
                mainHandler.post(callback::onSuccess);
            }
        });
    }

    public boolean isAuthenticated() {
        return securityManager.isSessionValid();
    }
}

