// ============================================

package com.securebank.app.ui;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.securebank.app.R;
import com.securebank.app.security.BiometricAuthManager;
import com.securebank.app.security.RootDetector;
import com.securebank.app.service.AuthService;

public class LoginActivity extends AppCompatActivity {

    private EditText usernameInput;
    private EditText pinInput;
    private Button loginButton;
    private Button biometricButton;
    private ProgressBar progressBar;
    private TextView errorText;
    private TextView rootWarningText;

    private AuthService authService;
    private int failedAttempts = 0;
    private static final int MAX_FAILED_ATTEMPTS = 5;
    private long lockoutEndTime = 0;
    private static final long LOCKOUT_DURATION_MS = 30000;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        getWindow().setFlags(
                WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE
        );

        setContentView(R.layout.activity_login);

        authService = AuthService.getInstance();

        if (authService.isAuthenticated()) {
            navigateToDashboard();
            return;
        }

        initViews();
        setupListeners();
        checkDeviceSecurity();
    }

    private void initViews() {
        usernameInput = findViewById(R.id.et_username);
        pinInput = findViewById(R.id.et_pin);
        loginButton = findViewById(R.id.btn_login);
        biometricButton = findViewById(R.id.btn_biometric);
        progressBar = findViewById(R.id.progress_bar);
        errorText = findViewById(R.id.tv_error);
        rootWarningText = findViewById(R.id.tv_root_warning);

        if (BiometricAuthManager.isBiometricAvailable(this)) {
            biometricButton.setVisibility(View.VISIBLE);
        } else {
            biometricButton.setVisibility(View.GONE);
        }
    }

    private void setupListeners() {
        loginButton.setOnClickListener(v -> attemptLogin());

        biometricButton.setOnClickListener(v -> attemptBiometricLogin());
    }

    private void checkDeviceSecurity() {
        if (RootDetector.isDeviceRooted()) {
            rootWarningText.setVisibility(View.VISIBLE);
            rootWarningText.setText(
                    "Warning: This device may be compromised. " +
                            "Some features may be restricted.");
        }
    }

    private void attemptLogin() {
        if (isLockedOut()) {
            long remainingSeconds = (lockoutEndTime - System.currentTimeMillis()) / 1000;
            showError("Too many failed attempts. Please wait " +
                    remainingSeconds + " seconds.");
            return;
        }

        String username = usernameInput.getText().toString().trim();
        String pin = pinInput.getText().toString().trim();

        if (username.isEmpty()) {
            usernameInput.setError("Username is required");
            usernameInput.requestFocus();
            return;
        }

        if (pin.isEmpty()) {
            pinInput.setError("PIN is required");
            pinInput.requestFocus();
            return;
        }

        showLoading(true);
        hideError();

        authService.login(username, pin, new AuthService.AuthCallback() {
            @Override
            public void onSuccess() {
                showLoading(false);
                failedAttempts = 0;
                pinInput.setText("");
                navigateToDashboard();
            }

            @Override
            public void onError(String errorMessage) {
                showLoading(false);
                failedAttempts++;
                pinInput.setText("");

                if (failedAttempts >= MAX_FAILED_ATTEMPTS) {
                    lockoutEndTime = System.currentTimeMillis() + LOCKOUT_DURATION_MS;
                    showError("Too many failed attempts. Account temporarily locked.");
                } else {
                    int remaining = MAX_FAILED_ATTEMPTS - failedAttempts;
                    showError(errorMessage + " (" + remaining + " attempts remaining)");
                }
            }
        });
    }

    private void attemptBiometricLogin() {
        BiometricAuthManager.authenticate(this,
                "Secure Bank Login",
                "Authenticate to access your account",
                new BiometricAuthManager.BiometricCallback() {
                    @Override
                    public void onAuthenticationSuccess() {
                        navigateToDashboard();
                    }

                    @Override
                    public void onAuthenticationError(String error) {
                        showError("Biometric authentication failed: " + error);
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        showError("Biometric authentication failed. Please try again.");
                    }
                });
    }

    private boolean isLockedOut() {
        return System.currentTimeMillis() < lockoutEndTime;
    }

    private void showLoading(boolean show) {
        progressBar.setVisibility(show ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!show);
        biometricButton.setEnabled(!show);
        usernameInput.setEnabled(!show);
        pinInput.setEnabled(!show);
    }

    private void showError(String message) {
        errorText.setText(message);
        errorText.setVisibility(View.VISIBLE);
    }

    private void hideError() {
        errorText.setVisibility(View.GONE);
    }

    private void navigateToDashboard() {
        Intent intent = new Intent(this, DashboardActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }

    @Override
    protected void onPause() {
        super.onPause();
        pinInput.setText("");
    }
}

